// Highlights the clicked todo list row and clears the highlight from the others.
// The right pane is loaded via a Turbo Frame, so the left rows aren't re-rendered;
// this keeps the "selected" styling in sync on the client.
export default class extends Controller {
  static targets = ["row"]

  static SELECTED = ["border-indigo-400", "bg-indigo-50"]
  static UNSELECTED = ["border-slate-200", "hover:bg-slate-50"]

  select(event) {
    const row = event.currentTarget.closest("[data-selection-target='row']")
    if (!row) return

    this.rowTargets.forEach((other) => {
      other.classList.remove(...this.constructor.SELECTED)
      other.classList.add(...this.constructor.UNSELECTED)
    })

    row.classList.remove(...this.constructor.UNSELECTED)
    row.classList.add(...this.constructor.SELECTED)
  }
}

