    if (!row) return

    this.rowTargets.forEach((other) => {
      other.classList.remove(...this.constructor.SELECTED)
      other.classList.add(...this.constructor.UNSELECTED)
    })

    row.classList.remove(...this.constructor.UNSELECTED)
    row.classList.add(...this.constructor.SELECTED)
  }
}

