input.expression:
(() => {
  const btn = document.querySelector('[data-confirmation-target="confirmButton"]');
  const r = btn.getBoundingClientRect();
  const el = document.elementFromPoint(Math.round(r.left + r.width/2), Math.round(r.top + r.height/2));
  el.click();
  return { clicked: el === btn || btn.contains(el) };
})()

